<template>
  <el-container>
    <el-header>
      <el-row type="flex" justify="space-between">
        <el-col :span="4"> <span>后台管理系统</span> </el-col>
        <el-col :span="4">
          <el-button type="info" @click="logout">退出</el-button>
        </el-col>
      </el-row>
    </el-header>
    <el-container>
      <el-aside :width="asideWidth">
        <div class="collapseBar" @click="collapseChange">|||</div>
        <!-- 如果想要使用menu的路由属性，必须给相应的导航的index属性设置成路由全路径，router-link to属性一样 -->
        <el-menu
          :default-active="activeMenu"
          class="el-menu-vertical-demo"
          background-color="rgb(51, 55, 68)"
          text-color="#fff"
          active-text-color="#62d9ef"
          :collapse="collapsed"
          :collapse-transition="false"
          router
        >
          <el-submenu
            v-for="item in menuList"
            :key="item.id + ''"
            :index="item.id + ''"
          >
            <template slot="title">
              <i class="iconfont" :class="icons[item.id]"></i>
              <span>{{ item.authName }}</span>
            </template>
            <el-menu-item
              v-for="child in item.children"
              :key="child.id + ''"
              :index="'/admin/' + child.path"
              @click="changeActiveMuenu('/admin/' + child.path)"
            >
              <i class="el-icon-menu"></i>
              <template slot="title">{{ child.authName }}</template>
            </el-menu-item>
          </el-submenu>
        </el-menu>
      </el-aside>
      <el-main>
        <router-view></router-view>
      </el-main>
    </el-container>
  </el-container>
</template>
<script>
import { mapMutations, mapState } from 'vuex'
export default {
  created() {
    this.getUserMenu()
  },
  name: 'admin',
  data() {
    return {
      // 动态类名绑定
      icons: {
        125: 'icon-yonghu',
        103: 'icon-jiaosequanxian',
        101: 'icon-shangpin2',
        102: 'icon-5',
        145: 'icon-zhexiantu'
      },
      
      collapsed: false,
      asideWidth: '200px'
    }
  },
  computed: {
    ...mapState(['activeMenu', 'menuList'])
  },
  methods: {
    ...mapMutations(['setActiveMenu', 'initMenu']),
    logout() {
      // 清除登陆信息
      window.sessionStorage.clear()
      this.$router.push({ name: 'login' })
    },
    async getUserMenu() {
      let {
        data: { data: res }
      } = await this.$http.get('/menus')
      this.initMenu(res)
    },
    changeActiveMuenu(active) {
      this.setActiveMenu(active)
    },
    collapseChange() {
      this.collapsed = !this.collapsed
      if (this.collapsed) {
        this.asideWidth = '65px'
      } else {
        this.asideWidth = '200px'
      }
    }
  }
}
</script>
<style lang="less" scoped>
.el-container {
  height: 100%;
}
.el-header {
  background-color: rgb(55, 61, 65);
}
.el-row {
  height: 60px;
  .el-col {
    text-align: center;
    line-height: 60px;
    span {
      font-size: 18px;
      color: #fff;
      font-weight: bold;
    }
  }
}
.el-aside {
  background-color: rgb(51, 55, 68);
}
.iconfont {
  margin-right: 10px;
}
.el-aside {
  .el-menu {
    border: none;
  }
}
.collapseBar {
  width: 100%;
  height: 30px;
  user-select: none;
  font-size: 14px;
  color: #fff;
  line-height: 30px;
  text-align: center;
  letter-spacing: 2px;
  background-color: rgb(45, 47, 54);
  cursor: pointer;
}
</style>
