<template>
  <div>
    <Bread></Bread>
    <el-card>
      <el-row :gutter="20">
        <el-col :span="8">
          <el-input
            placeholder="请输入内容"
            v-model.trim="requestParams.query"
            clearable
            @clear="getUsers()"
          >
            <el-button
              @click="getUsers()"
              slot="append"
              icon="el-icon-search"
            ></el-button>
          </el-input>
        </el-col>
        <el-col :span="8">
          <el-button type="primary" @click="addDialogVisible = true"
            >添加用户</el-button
          >
        </el-col>
      </el-row>

      <el-table :data="userList" border style="width: 100%" stripe>
        <el-table-column type="index" width="50"></el-table-column>
        <el-table-column prop="username" label="姓名"> </el-table-column>
        <el-table-column prop="email" label="邮箱" width="200px">
        </el-table-column>
        <el-table-column prop="mobile" label="电话"> </el-table-column>
        <el-table-column prop="role_name" label="角色"> </el-table-column>
        <el-table-column prop="mg_state" label="状态">
          <template v-slot:default="scope">
            <el-switch
              @change="userStateChange(scope.row)"
              v-model="scope.row.mg_state"
              active-color="#13ce66"
              inactive-color="#ff4949"
            >
            </el-switch>
          </template>
        </el-table-column>
        <el-table-column label="操作" width="200px">
          <template v-slot:default="scope">
            <el-tooltip
              :enterable="false"
              class="item"
              effect="dark"
              content="编辑"
              placement="top"
            >
              <el-button
                type="primary"
                icon="el-icon-edit"
                size="mini"
                @click="editUser(scope.row.id)"
              ></el-button>
            </el-tooltip>
            <el-tooltip
              :enterable="false"
              class="item"
              effect="dark"
              content="删除"
              placement="top"
            >
              <el-button
                type="danger"
                icon="el-icon-delete"
                size="mini"
                @click="deleteUser(scope.row.id)"
              ></el-button>
            </el-tooltip>
            <el-tooltip
              :enterable="false"
              class="item"
              effect="dark"
              content="修改权限"
              placement="top"
            >
              <el-button
                type="warning"
                icon="el-icon-setting"
                size="mini"
              ></el-button>
            </el-tooltip>
          </template>
        </el-table-column>
      </el-table>

      <el-pagination
        @current-change="handleCurrentChange"
        @size-change="handleSizeChange"
        :current-page="requestParams.pagenum"
        :page-sizes="[1, 2, 5, 10]"
        :page-size="requestParams.pagesize"
        layout="total, sizes, prev, pager, next, jumper"
        :total="totalpage"
      >
      </el-pagination>
      <el-dialog title="添加用户" width="70%" :visible.sync="addDialogVisible">
        <el-form
          ref="addForm"
          :model="addForm"
          autocomplete="off"
          :rules="rules"
        >
          <el-form-item
            prop="username"
            label="用户名"
            :label-width="formLabelWidth"
          >
            <el-input v-model="addForm.username" autocomplete="off"></el-input>
          </el-form-item>
          <el-form-item
            prop="password"
            label="密码"
            :label-width="formLabelWidth"
          >
            <el-input
              v-model="addForm.password"
              type="password"
              autocomplete="off"
            ></el-input>
          </el-form-item>
          <el-form-item
            label="电话号码"
            prop="mobile"
            :label-width="formLabelWidth"
          >
            <el-input v-model="addForm.mobile" autocomplete="off"></el-input>
          </el-form-item>
          <el-form-item label="邮箱" prop="email" :label-width="formLabelWidth">
            <el-input v-model="addForm.email" autocomplete="off"></el-input>
          </el-form-item>
        </el-form>
        <div slot="footer" class="dialog-footer">
          <el-button @click="addReset">取 消</el-button>
          <el-button type="primary" @click="addSubmit">确 定</el-button>
        </div>
      </el-dialog>

      <el-dialog title="编辑用户" width="70%" :visible.sync="editDialogVisible">
        <el-form
          ref="editForm"
          :model="editForm"
          autocomplete="off"
          :rules="rules"
        >
          <el-form-item
            prop="username"
            label="用户名"
            :label-width="formLabelWidth"
          >
            <el-input
              disabled
              v-model="editForm.username"
              autocomplete="off"
            ></el-input>
          </el-form-item>
          <el-form-item
            label="电话号码"
            prop="mobile"
            :label-width="formLabelWidth"
          >
            <el-input v-model="editForm.mobile" autocomplete="off"></el-input>
          </el-form-item>
          <el-form-item label="邮箱" prop="email" :label-width="formLabelWidth">
            <el-input v-model="editForm.email" autocomplete="off"></el-input>
          </el-form-item>
        </el-form>
        <div slot="footer" class="dialog-footer">
          <el-button @click="editReset">取 消</el-button>
          <el-button type="primary" @click="editSubmit">确 定</el-button>
        </div>
      </el-dialog>

      <el-dialog title="提示" :visible.sync="deleteDialogVisible" width="30%">
        <span>是否确认删除</span>
        <span slot="footer" class="dialog-footer">
          <el-button @click="cancleDelete">取 消</el-button>
          <el-button type="primary" @click="confirmDelete">确 定</el-button>
        </span>
      </el-dialog>
    </el-card>
  </div>
</template>
<script>
import Bread from '@/components/Bread.vue'
export default {
  name: 'users',
  created() {
    this.getUsers()
  },
  data() {
    var validateEmail = (rule, value, callback) => {
      var ePattern =
        /^([A-Za-z0-9_\-\.])+\@([A-Za-z0-9_\-\.])+\.([A-Za-z]{2,4})$/
      if (ePattern.test(value)) {
        // 校验成功执行回调
        callback()
      } else {
        callback(new Error('邮箱格式不正确'))
      }
    }
    var validateMobile = (rule, value, callback) => {
      var mPattern = /^1[34578]\d{9}$/
      if (mPattern.test(value)) {
        // 校验成功执行回调
        callback()
      } else {
        callback(new Error('手机号格式不正确'))
      }
    }
    return {
      requestParams: {
        // 搜索内容
        query: '',
        // 当前页码
        pagenum: 1,
        pagesize: 5
      },
      userList: [],
      totalpage: 0,
      // 添加表单的显示隐藏状态
      addDialogVisible: false,
      editDialogVisible: false,
      deleteDialogVisible: false,
      // label标签的宽度
      formLabelWidth: '120px',
      addForm: {
        username: '',
        password: '',
        mobile: '',
        email: ''
      },
      editForm: {
        id: '',
        rid: '',
        username: '',
        mobile: '',
        email: ''
      },
      deleteId: '',
      // 添加和编辑表单的校验规则
      rules: {
        username: [
          { required: true, message: '请输入用户名', trigger: 'blur' },
          { min: 3, max: 10, message: '长度在 3 到 10 个字符', trigger: 'blur' }
        ],
        password: [
          { required: true, message: '请输入密码', trigger: 'blur' },
          { min: 5, max: 10, message: '长度在 5 到 10 个字符', trigger: 'blur' }
        ],
        mobile: [
          { required: true, message: '请输入电话', trigger: 'blur' },
          { validator: validateMobile, trigger: 'blur' }
        ],
        email: [
          { required: true, message: '请输入邮箱', trigger: 'blur' },
          { validator: validateEmail, trigger: 'blur' }
        ]
      }
    }
  },
  methods: {
    handleCurrentChange(val) {
      this.requestParams.pagenum = val
      this.getUsers()
    },
    handleSizeChange(val) {
      this.requestParams.pagesize = val
      this.getUsers()
    },
    async getUsers() {
      let { data } = await this.$http.get('/users', {
        params: this.requestParams
      })
      this.userList = data.data.users
      this.totalpage = data.data.total
    },
    // 修改用户状态
    async userStateChange(data) {
      let { data: res } = await this.$http.put(
        `/users/${data.id}/state/${data.mg_state}`
      )
      if (res.meta.status !== 200) {
        return this.$message.error(res.meta.msg)
      }
      this.$message.success(res.meta.msg)
    },
    // 提交添加用户
    addSubmit() {
      this.$refs.addForm.validate(async valid => {
        if (valid) {
          // 校验成功，发送ajax
          // 关闭弹窗并提示
          let { data: res } = await this.$http.post('/users', this.addForm)
          if (res.meta.status !== 201) {
            this.$message.error(res.meta.msg)
          } else {
            this.$message.success(res.meta.msg)
          }
        } else {
          // 校验失败,重置表单内容,关闭弹窗并提示
          // 提示
          this.$message.error('输入内容格式不正确')
        }
        // 重置表单
        this.$refs.addForm.resetFields()
        // 关闭弹窗
        this.addDialogVisible = false
        this.getUsers()
      })
    },
    addReset() {
      this.$refs.addForm.resetFields()
      // 关闭弹窗
      this.addDialogVisible = false
    },
    // 根据id查询用户信息
    async editUser(id) {
      let { data: res } = await this.$http.get('/users/' + id)
      if (res.meta.status !== 200) {
        this.$message.error(res.meta.msg)
      } else {
        this.editForm = res.data
        this.editDialogVisible = true
      }
    },
    // 用户编辑
    editSubmit() {
      this.$refs.editForm.validate(async valid => {
        if (valid) {
          // 校验成功，发送ajax
          // 关闭弹窗并提示
          // put 提交和post一样，不需要使用 query或者params
          let { data: res } = await this.$http.put(
            '/users/' + this.editForm.id,
            {
              email: this.editForm.email,
              mobile: this.editForm.mobile
            }
          )
          if (res.meta.status !== 200) {
            this.$message.error(res.meta.msg)
          } else {
            this.$message.success(res.meta.msg)
          }
        } else {
          // 校验失败,重置表单内容,关闭弹窗并提示
          // 提示
          this.$message.error('输入内容格式不正确')
        }
        // 重置表单
        // 关闭弹窗
        this.editDialogVisible = false
        this.getUsers()
      })
    },
    editReset() {
      // 关闭弹窗
      this.editDialogVisible = false
    },
    deleteUser(id) {
      // 弹窗
      this.deleteId = id
      this.deleteDialogVisible = true
    },
    cancleDelete() {
      this.deleteId = ''
      this.deleteDialogVisible = false
    },
    async confirmDelete() {
      let { data: res } = await this.$http.delete('/users/' + this.deleteId)
      if (res.meta.status !== 200) {
        this.$message.error(res.meta.msg)
      } else {
        this.$message.success(res.meta.msg)
        this.getUsers()
      }
      this.deleteId = ''
      this.deleteDialogVisible = false
    }
  },
  components: {
    Bread
  }
}
</script>
<style scoped>
.el-table {
  margin: 20px 0;
  font-size: 12px;
}
</style>
