import Vue from 'vue'
import VueRouter from 'vue-router'
import Login from '../views/Login.vue'
import Admin from '../views/Admin.vue'
import Welcome from '../views/Welcome.vue'
import User from '../views/User.vue'
import Role from '../views/Roles.vue'

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    redirect: '/login'
  },
  {
    path: '/login',
    name: 'login',
    component: Login
  },
  {
    path: '/admin',
    name: 'admin',
    component: Admin,
    redirect: '/admin/welcome',
    children: [
      {
        path: 'welcome',
        name: 'welcome',
        component: Welcome
      },
      {
        path: 'users',
        name: 'users',
        component: User,
        // 当用户层级嵌套浅的时候,面包屑可以写在meta当中
        meta: {
          route: ['用户管理', '用户列表']
        }
      },
      {
        path: 'roles',
        name: 'roles',
        component: Role,
        // 当用户层级嵌套浅的时候,面包屑可以写在meta当中
        meta: {
          route: ['权限管理', '角色列表']
        }
      }
    ]
  }
]

const router = new VueRouter({
  routes
})

router.beforeEach((to, from, next) => {
  if (to.path === '/login') {
    next()
  } else {
    let token = window.sessionStorage.getItem('token')
    if (token) {
      next()
    } else {
      next('/login')
    }
  }
})

export default router
