<template>
  <el-breadcrumb separator-class="el-icon-arrow-right">
    <el-breadcrumb-item
      ><a @click="clearActive">后台管理</a></el-breadcrumb-item
    >
    <el-breadcrumb-item v-for="item in $route.meta.route" :key="item">{{
      item
    }}</el-breadcrumb-item>
  </el-breadcrumb>
</template>
<script>
import { mapGetters, mapMutations } from 'vuex'
export default {
  name: 'bread',
  computed: {
    ...mapGetters(['menuList'])
  },
  methods: {
    ...mapMutations(['setActiveMenu']),
    clearActive() {
      this.setActiveMenu('')
      this.$router.push({ name: 'admin' })
    }
  }
}
</script>
<style scoped>
.el-breadcrumb {
  margin-bottom: 20px;
}
</style>
